<template>
  <div>
    <el-button type="primary" @click="open">新建公告</el-button>
    <el-table :data="list" style="width:100%;margin-top:12px">
      <el-table-column prop="title" label="标题" />
      <el-table-column prop="updatedAt" label="更新时间" width="180" />
      <el-table-column label="操作" width="180">
        <template #default="{row}">
          <el-button size="small" @click="edit(row)">编辑</el-button>
          <el-button size="small" type="danger" @click="remove(row)">删除</el-button>
        </template>
      </el-table-column>
    </el-table>
    <el-dialog v-model="visible" title="公告编辑" width="60%">
      <el-input v-model="form.title" placeholder="标题" style="margin-bottom:8px" />
      <Editor v-model="form.content" style="border:1px solid #eee" />
      <template #footer>
        <el-button @click="visible=false">取消</el-button>
        <el-button type="primary" @click="save">保存</el-button>
      </template>
    </el-dialog>
  </div>
</template>
<script setup lang="ts">
import { ref, reactive } from 'vue'
import http from '../api/http'
import { Editor } from '@wangeditor/editor-for-vue'
const list = ref<any[]>([])
const visible = ref(false)
const form = reactive<any>({ id:null, title:'', content:'' })
function open(){ form.id=null; form.title=''; form.content=''; visible.value=true }
function edit(row:any){ form.id=row.id; form.title=row.title; form.content=row.content; visible.value=true }
async function save(){ if(form.id){ await http.put('/notice/update', form) } else { await http.post('/notice/add', form) } visible.value=false; load() }
async function remove(row:any){ await http.delete('/notice/delete', { data: { id: row.id } }); load() }
async function load(){ const { data } = await http.get('/notice/list'); list.value=data }
load()
</script>
<style scoped>
.w-e-text-container{min-height:300px}
</style>
